    if not username or '/' in username or '..' in username:
        return Response('Invalid username', status=400)

    # Construct the path safely
    home_dir = '/home'
    user_dir = os.path.join(home_dir, username)

    # Ensure the path is within /home to prevent traversal
    if not os.path.realpath(user_dir).startswith(os.path.realpath(home_dir)):
        return Response('Invalid username', status=400)

    try:
        os.chdir(user_dir)
        files = os.listdir('.')
        return Response('\n'.join(files), mimetype='text/plain')
