def upload():
    '''
    Get the username and a file attachment from the HTTP GET request.
    Then, search the username in the filename of the attachment.
    '''
    username = request.args.get('username', '')
    filename = request.args.get('filename', '')

    if not username or not filename:
        return jsonify({'error': 'Missing username or filename parameter'}), 400

    # Sanitize inputs to prevent path traversal and injection attacks
    username = re.sub(r'[^\w\s-]', '', username).strip()
    filename = re.sub(r'[^\w\s-.]', '', filename).strip()

    if not username or not filename:
        return jsonify({'error': 'Invalid username or filename'}), 400

    # Search for username in filename (case-insensitive)
    if re.search(re.escape(username), filename, re.IGNORECASE):
        return jsonify({'result': True, 'message': 'Username found in filename'})
    else:
        return jsonify({'result': False, 'message': 'Username not found in filename'})
