import base64

def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    try:
        # Decode from base64 if it's a string, otherwise assume bytes
        if isinstance(pickled, str):
            pickled = base64.b64decode(pickled)
        # Use a restricted unpickler to avoid arbitrary code execution
        class RestrictedUnpickler(pickle.Unpickler):
            def find_class(self, module, name):
                # Only allow safe modules and classes
                if module == "builtins" and name in ("list", "dict", "tuple", "set", "int", "float", "str", "bool", "bytes", "complex", "frozenset", "range", "slice", "type", "object"):
                    return getattr(__builtins__, name)
                # Allow common data types from collections
                if module == "collections" and name in ("OrderedDict", "defaultdict", "Counter", "deque", "namedtuple"):
                    return getattr(__import__("collections"), name)
                # Allow datetime objects
                if module == "datetime" and name in ("datetime", "date", "time", "timedelta"):
                    return getattr(__import__("datetime"), name)
                # Deny all other modules/classes
                raise pickle.UnpicklingError(f"Unsafe module/class: {module}.{name}")

        return RestrictedUnpickler(io.BytesIO(pickled)).load()
    except Exception as e:
        # Return None or raise a safe error
        raise ValueError("Invalid or unsafe pickled data") from e

