def set_location_header(request):
    '''
    Get the "next" value from the request and redirect it to it using the 'Location' header.
    '''
    next_url = request.GET.get('next', '/')

    # Validate the URL to prevent open redirect vulnerabilities
    parsed = urlparse(next_url)

    # Only allow relative URLs or same-origin URLs
    if parsed.netloc and parsed.netloc != request.get_host():
        return HttpResponseRedirect('/')

    # Ensure the URL is safe (no javascript: or other dangerous schemes)
    if parsed.scheme and parsed.scheme not in ['http', 'https', '']:
        return HttpResponseRedirect('/')

    # Check if the path is a valid Django URL (optional but recommended)
    try:
        resolve(parsed.path)
    except Resolver404:
        return HttpResponseRedirect('/')

    return HttpResponseRedirect(next_url)

