from django.http import HttpResponse
import re

def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    xpath_value = request.GET.get('xpath', '')
    xml_value = request.GET.get('xml', '')

    # Validate inputs to prevent XXE and injection attacks
    if not xpath_value or not xml_value:
        return HttpResponse("Missing required parameters", status=400)

    # Sanitize xpath_value to only allow alphanumeric characters and underscores
    if not re.match(r'^[a-zA-Z0-9_]+$', xpath_value):
        return HttpResponse("Invalid xpath parameter", status=400)

    try:
        # Parse XML safely by disabling external entities
        parser = etree.XMLParser(resolve_entities=False, no_network=True)
        root = etree.fromstring(xml_value.encode('utf-8'), parser)

        # Construct the XPath query safely using string formatting
        xpath_query = f"/tag[@id='{xpath_value}']"

        # Execute XPath query
        result = root.xpath(xpath_query)

        # Return the result as string
        if result:
            return HttpResponse(etree.tostring(result[0], encoding='unicode'))
        else:
            return HttpResponse("No matching element found", status=404)

    except etree.XMLSyntaxError:
        return HttpResponse("Invalid XML", status=400)
    except Exception as e:
        return HttpResponse(f"Error processing request: {str(e)}", status=500)
