def retrieve_info():
    '''
    Get the user_id from the request,
    retrieve the user info from GitHub using the GitHub's API,
    and return the response
    '''
    user_id = request.args.get('user_id')

    if not user_id:
        return jsonify({"error": "Missing user_id parameter"}), 400

    # Validate user_id to prevent injection attacks
    if not isinstance(user_id, str) or not user_id.isalnum():
        return jsonify({"error": "Invalid user_id format"}), 400

    # Use a timeout to prevent hanging requests
    try:
        response = requests.get(
            f"https://api.github.com/users/{user_id}",
            timeout=10
        )
        response.raise_for_status()
        return jsonify(response.json())
    except requests.exceptions.Timeout:
        return jsonify({"error": "Request timed out"}), 504
    except requests.exceptions.HTTPError as e:
        if response.status_code == 404:
            return jsonify({"error": "User not found"}), 404
        return jsonify({"error": "GitHub API error"}), response.status_code
    except requests.exceptions.RequestException:
        return jsonify({"error": "Failed to fetch user info"}), 500
